  1	import * as React from 'react';
  2	import {
  3	  useK8sWatchResource,
  4	  useK8sWatchResources,
  5	  WatchK8sResource,
  6	} from '@openshift-console/dynamic-plugin-sdk';
  7	import { K8sModel } from '@openshift-console/dynamic-plugin-sdk/lib/api/common-types';
  8	import classNames from 'classnames';
  9	import * as fuzzy from 'fuzzysearch';
 10	import * as _ from 'lodash-es';
 11	import {
 12	  TextInput,
 13	  Dropdown,
 14	  DropdownItem,
 15	  DropdownList,
 16	  MenuToggle,
 17	  MenuToggleElement,
 18	} from '@patternfly/react-core';
 19	import { LoadingInline } from '../generic/Loading';
 20	import { getName, getUID } from '../selectors';
 21	import { useCustomTranslation } from '../useCustomTranslationHook';
 22	import '../style.scss';
 23	import './resourceDropdown.scss';
 24	
 25	const filterName = (searchText: string, resourceName: string) =>
 26	  fuzzy(searchText, resourceName);
 27	
 28	type ResourceBadgeProps = {
 29	  model: K8sModel;
 30	};
 31	
 32	const ResourceBadge: React.FC<ResourceBadgeProps> = ({
 33	  model: resourceModel,
 34	}) => (
 35	  <>
 36	    <span className="sr-only">{resourceModel.abbr.toLocaleUpperCase()}</span>
 37	    <span className="odf-m-resource-icon" title={resourceModel.kind}>
 38	      {resourceModel.abbr.toLocaleUpperCase()}
 39	    </span>
 40	  </>
 41	);
 42	
 43	type ResourceDropdownItemProps<T> = {
 44	  resource: T;
 45	  resourceModel: K8sModel;
 46	  id: string;
 47	  propertySelector?: (resource: T) => string;
 48	  showBadge?: boolean;
 49	  secondaryTextGenerator?: (resource: T) => string;
 50	  onClick?: any;
 51	  onBlur?: () => void;
 52	  'data-test'?: string;
 53	};
 54	
 55	type ResourceDropdownItem = <T>(
 56	  props: ResourceDropdownItemProps<T>
 57	) => ReturnType<React.FC>;
 58	
 59	const ResourceDropdownItem: ResourceDropdownItem = ({
 60	  resourceModel: model,
 61	  resource,
 62	  propertySelector,
 63	  showBadge = true,
 64	  id,
 65	  secondaryTextGenerator,
 66	  onClick,
 67	  'data-test': dataTest,
 68	}) => {
 69	  return (
 70	    <DropdownItem data-test={dataTest} id={id} onClick={onClick}>
 71	      <div>
 72	        <span className="odf-resource-item">
 73	          {showBadge && <ResourceBadge model={model} />}
 74	          {propertySelector(resource)}
 75	        </span>
 76	      </div>
 77	      {secondaryTextGenerator && (
 78	        <div>
 79	          <span className="text-muted">{secondaryTextGenerator(resource)}</span>
 80	        </div>
 81	      )}
 82	    </DropdownItem>
 83	  );
 84	};
 85	
 86	type ResourceDropdownTextProps = {
 87	  showBadge?: boolean;
 88	  resourceModel?: K8sModel;
 89	  text: string;
 90	  className?: string;
 91	};
 92	
 93	const ResourceDropdownText: React.FC<ResourceDropdownTextProps> = ({
 94	  showBadge = true,
 95	  resourceModel,
 96	  text,
 97	  className,
 98	}) => (
 99	  <span className={className}>
100	    {text && showBadge && <ResourceBadge model={resourceModel} />}
101	    {text}
102	  </span>
103	);
104	
105	type ResourceDropdownProps<T> = {
106	  resource: WatchK8sResource;
107	  resourceModel: K8sModel;
108	  onSelect: (resource: T) => void;
109	  onBlur?: () => void;
110	  secondaryTextGenerator?: (resource: T) => string;
111	  propertySelector?: (resource: T) => string;
112	  showBadge?: boolean;
113	  className?: string;
114	  initialSelection?: (resource: T[]) => T;
115	  filterResource?: (resource: T) => boolean;
116	  isDisabled?: boolean;
117	  'data-test'?: string;
118	  id?: string;
119	  selectedResource?: T;
120	};
121	
122	type ResourceDropdown = <T>(
123	  props: React.PropsWithChildren<ResourceDropdownProps<T>>
124	) => ReturnType<React.FC>;
125	
126	const ResourceDropdown: ResourceDropdown = <T extends unknown>({
127	  resource: watchResource,
128	  resourceModel,
129	  showBadge,
130	  propertySelector = getName,
131	  onSelect,
132	  onBlur,
133	  secondaryTextGenerator,
134	  className,
135	  initialSelection,
136	  filterResource,
137	  isDisabled = false,
138	  'data-test': dataTest,
139	  id,
140	  children,
141	}) => {
142	  const [isOpen, setOpen] = React.useState(false);
143	  const [selectedItem, setSelectedItem] = React.useState(null);
144	  const [searchText, setSearchText] = React.useState('');
145	
146	  const { t } = useCustomTranslation();
147	
148	  const [resources = [], loaded, loadError] =
149	    useK8sWatchResource<T[]>(watchResource);
150	
151	  React.useEffect(() => {
152	    if (
153	      _.isFunction(initialSelection) &&
154	      _.isEmpty(selectedItem) &&
155	      loaded &&
156	      !loadError
157	    ) {
158	      const item = initialSelection(resources);
159	      onSelect(item);
160	      setSelectedItem(item);
161	    }
162	  }, [
163	    selectedItem,
164	    initialSelection,
165	    setSelectedItem,
166	    loaded,
167	    loadError,
168	    resources,
169	    onSelect,
170	  ]);
171	
172	  const onClick = React.useCallback(
173	    (event: React.SyntheticEvent<HTMLDivElement>) => {
174	      const resourceName = event?.currentTarget?.id;
175	      const selectedResource = resources.find(
176	        (resource) => getName(resource) + '-link' === resourceName
177	      );
178	      onSelect(selectedResource);
179	      setSelectedItem(selectedResource);
180	      setOpen(false);
181	    },
182	    [onSelect, setSelectedItem, resources]
183	  );
184	
185	  const dropdownItems = React.useMemo(() => {
186	    if (!loaded && loadError) {
187	      return [];
188	    } else {
189	      return resources
190	        .filter(
191	          (res) =>
192	            filterName(searchText, getName(res)) &&
193	            (filterResource ? filterResource(res) : true)
194	        )
195	        .sort((a, b) => getName(a).localeCompare(getName(b)))
196	        .reduce((acc, curr) => {
197	          return [
198	            ...acc,
199	            <ResourceDropdownItem<T>
200	              key={propertySelector(curr)}
201	              resourceModel={resourceModel}
202	              showBadge={showBadge}
203	              resource={curr}
204	              id={`${getName(curr)}-link`}
205	              propertySelector={propertySelector}
206	              secondaryTextGenerator={secondaryTextGenerator}
207	              onClick={onClick}
208	              onBlur={onBlur}
209	              data-test="dropdown-menu-item-link"
210	            />,
211	          ];
212	        }, []);
213	    }
214	  }, [
215	    resources,
216	    loaded,
217	    loadError,
218	    resourceModel,
219	    showBadge,
220	    propertySelector,
221	    secondaryTextGenerator,
222	    onClick,
223	    onBlur,
224	    searchText,
225	    filterResource,
226	  ]);
227	
228	  const onToggle = () => {
229	    setOpen((o) => !o);
230	    setSearchText('');
231	  };
232	
233	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
234	    <MenuToggle
235	      ref={toggleRef}
236	      onClick={onToggle}
237	      isExpanded={isOpen}
238	      data-test={dataTest}
239	      isDisabled={isDisabled || !loaded || loadError || _.isEmpty(resources)}
240	      isFullWidth
241	    >
242	      {!loaded && <LoadingInline />}
243	      {loaded &&
244	        !loadError &&
245	        (_.isEmpty(resources) ? (
246	          <span>{t('No resources available')}</span>
247	        ) : (
248	          <ResourceDropdownText
249	            text={
250	              selectedItem
251	                ? propertySelector(selectedItem)
252	                : t('Select {{resourceLabel}}', {
253	                    resourceLabel: resourceModel.label,
254	                  })
255	            }
256	            resourceModel={resourceModel}
257	            showBadge={selectedItem && showBadge}
258	            className={!selectedItem ? 'text-muted' : undefined}
259	          />
260	        ))}
261	      {loaded && loadError && (
262	        <span className="odf-resourceDropdownContainer__toggle--error">
263	          {t('Error Loading')}
264	        </span>
265	      )}
266	    </MenuToggle>
267	  );
268	
269	  return (
270	    <div className={classNames('odf-resourceDropdown__container', className)}>
271	      <Dropdown
272	        id={id}
273	        className={classNames(
274	          'odf-resourceDropdownHeight',
275	          'odf-resourceDropdownListItems'
276	        )}
277	        toggle={toggle}
278	        isOpen={isOpen}
279	        onOpenChange={(open: boolean) => setOpen(open)}
280	        popperProps={{ width: 'trigger' }}
281	      >
282	        <DropdownList>
283	          <TextInput
284	            id="search-bar"
285	            value={searchText}
286	            onChange={(_event, val) => setSearchText(val)}
287	            autoComplete="off"
288	          />
289	          {dropdownItems}
290	        </DropdownList>
291	      </Dropdown>
292	      {children?.(loaded, loadError, resources)}
293	    </div>
294	  );
295	};
296	
297	type ResourcesDropdownProps<T> = {
298	  resources: { [key: string]: WatchK8sResource };
299	} & Omit<ResourceDropdownProps<T>, 'resource'>;
300	
301	type ResourcesDropdown = <T>(
302	  props: React.PropsWithChildren<ResourcesDropdownProps<T>>
303	) => ReturnType<React.FC>;
304	
305	type ResourcesObject<T> = {
306	  [key: string]: {
307	    data: T[];
308	    loaded: boolean;
309	    loadError: any;
310	  };
311	};
312	
313	export const ResourcesDropdown: ResourcesDropdown = <T extends unknown>({
314	  resources: watchResources,
315	  resourceModel,
316	  showBadge,
317	  propertySelector = getName,
318	  onSelect,
319	  secondaryTextGenerator,
320	  className,
321	  initialSelection,
322	  selectedResource,
323	  filterResource,
324	}) => {
325	  const [isOpen, setOpen] = React.useState(false);
326	  const [selectedItem, setSelectedItem] = React.useState(null);
327	  const [searchText, setSearchText] = React.useState('');
328	
329	  const { t } = useCustomTranslation();
330	
331	  const resourcesObj: ResourcesObject<T> = useK8sWatchResources(watchResources);
332	
333	  const [data, loaded, loadError] = React.useMemo(() => {
334	    let loaded = false,
335	      loadError: any;
336	    let firstItr = true;
337	    let data: T[] = _.reduce(
338	      resourcesObj,
339	      (acc, curr) => {
340	        if (firstItr) {
341	          loaded = curr.loaded;
342	          firstItr = false;
343	        } else loaded = loaded && curr.loaded;
344	        loadError = loadError || curr.loadError;
345	        return [...acc, ...curr.data];
346	      },
347	      []
348	    );
349	    return [data, loaded, loadError];
350	  }, [resourcesObj]);
351	
352	  React.useEffect(() => {
353	    if (initialSelection && selectedItem === null && loaded && !loadError) {
354	      const item = initialSelection(data);
355	      onSelect(item);
356	      setSelectedItem(item);
357	    }
358	  }, [
359	    selectedItem,
360	    initialSelection,
361	    setSelectedItem,
362	    loaded,
363	    loadError,
364	    data,
365	    onSelect,
366	  ]);
367	
368	  const onClick = React.useCallback(
369	    (event: React.SyntheticEvent<HTMLDivElement>) => {
370	      const resourceUID = event?.currentTarget?.id;
371	      const selectedObject = data.find(
372	        (resource) => getUID(resource) === resourceUID
373	      );
374	      onSelect(selectedObject);
375	      setSelectedItem(selectedObject);
376	      setOpen(false);
377	    },
378	    [onSelect, setSelectedItem, data]
379	  );
380	
381	  const dropdownItems = React.useMemo(() => {
382	    if (!loaded && loadError) {
383	      return [];
384	    } else {
385	      return data
386	        .filter(
387	          (res) =>
388	            filterName(searchText, getName(res)) &&
389	            (filterResource ? filterResource(res) : true)
390	        )
391	        .reduce((acc, curr) => {
392	          return [
393	            ...acc,
394	            <ResourceDropdownItem<T>
395	              key={propertySelector(curr)}
396	              resourceModel={resourceModel}
397	              showBadge={showBadge}
398	              resource={curr}
399	              id={getUID(curr)}
400	              propertySelector={propertySelector}
401	              secondaryTextGenerator={secondaryTextGenerator}
402	              onClick={onClick}
403	            />,
404	          ];
405	        }, []);
406	    }
407	  }, [
408	    data,
409	    loaded,
410	    loadError,
411	    resourceModel,
412	    showBadge,
413	    propertySelector,
414	    secondaryTextGenerator,
415	    onClick,
416	    searchText,
417	    filterResource,
418	  ]);
419	
420	  const onToggle = () => {
421	    setOpen((o) => !o);
422	    setSearchText('');
423	  };
424	
425	  React.useEffect(() => {
426	    if (selectedResource && !_.isEqual(selectedItem, selectedResource)) {
427	      setSelectedItem(selectedResource);
428	    }
429	  }, [setSelectedItem, selectedResource, selectedItem]);
430	
431	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
432	    <MenuToggle
433	      ref={toggleRef}
434	      isDisabled={!loaded || loadError}
435	      onClick={onToggle}
436	      isExpanded={isOpen}
437	      isFullWidth
438	    >
439	      {!loaded && <LoadingInline />}
440	      {loaded && !loadError && (
441	        <ResourceDropdownText
442	          text={
443	            selectedItem
444	              ? propertySelector(selectedItem)
445	              : t('Select {{resourceLabel}}', {
446	                  resourceLabel: resourceModel.label,
447	                })
448	          }
449	          resourceModel={resourceModel}
450	          showBadge={selectedItem && showBadge}
451	          className={!selectedItem && 'text-muted'}
452	        />
453	      )}
454	      {loaded && loadError && (
455	        <span className="odf-resourceDropdownContainer__toggle--error">
456	          {t('Error Loading')}
457	        </span>
458	      )}
459	    </MenuToggle>
460	  );
461	
462	  return (
463	    <div className={classNames('odf-resourceDropdown__container', className)}>
464	      <Dropdown
465	        className={classNames(
466	          'odf-resourceDropdownHeight',
467	          'odf-resourceDropdownListItems'
468	        )}
469	        toggle={toggle}
470	        isOpen={isOpen}
471	        onOpenChange={(open: boolean) => setOpen(open)}
472	        popperProps={{ width: 'trigger' }}
473	      >
474	        <DropdownList>
475	          <TextInput
476	            id="search-bar"
477	            value={searchText}
478	            onChange={(_event, val) => setSearchText(val)}
479	            autoComplete="off"
480	          />
481	          {dropdownItems}
482	        </DropdownList>
483	      </Dropdown>
484	    </div>
485	  );
486	};
487	
488	export default ResourceDropdown;

