  1	import React, { ReactNode } from 'react';
  2	import { Screen, render, screen } from '@testing-library/react';
  3	import userEvent from '@testing-library/user-event';
  4	import { SelectOptionProps } from '@patternfly/react-core';
  5	import { TypeaheadDropdown } from './TypeaheadDropdown';
  6	
  7	const getOption = (rtlScreen: Screen, name: ReactNode) =>
  8	  rtlScreen.queryByRole('option', {
  9	    name: new RegExp(name as string, 'i'),
 10	  });
 11	const getTypeaheadDropdown = (rtlScreen: Screen) =>
 12	  rtlScreen.getByRole<HTMLInputElement>('combobox', {
 13	    name: /type to filter/i,
 14	  });
 15	const items: SelectOptionProps[] = [
 16	  { value: '100', children: '100 TiB' },
 17	  { value: '120', children: '120 TiB' },
 18	  { value: '125', children: '125 TiB' },
 19	  { value: '200', children: '200 TiB' },
 20	  { value: '512', children: '512 TiB' },
 21	];
 22	let onSelect: jest.MockedFunction<(selected: string) => void>;
 23	
 24	describe('TypeaheadDropdown', () => {
 25	  it('has empty value if the preselected value does not match any option', () => {
 26	    const selectedValue = 'nonexistent';
 27	    render(<TypeaheadDropdown items={items} selectedValue={selectedValue} />);
 28	
 29	    expect(getTypeaheadDropdown(screen)).toHaveValue('');
 30	  });
 31	
 32	  it('selects the option value that matches the preselected value text', () => {
 33	    onSelect = jest.fn();
 34	    render(
 35	      <TypeaheadDropdown
 36	        items={items}
 37	        selectedValue="100"
 38	        onSelect={onSelect}
 39	      />
 40	    );
 41	
 42	    expect(getTypeaheadDropdown(screen)).toHaveValue(items[0].children);
 43	    expect(onSelect).not.toHaveBeenCalled();
 44	  });
 45	
 46	  it('selects the option value that matches the preselected value number', () => {
 47	    render(
 48	      <TypeaheadDropdown
 49	        items={items}
 50	        selectedValue={100}
 51	        onSelect={onSelect}
 52	      />
 53	    );
 54	
 55	    expect(getTypeaheadDropdown(screen)).toHaveValue(items[0].children);
 56	  });
 57	
 58	  it('selects the option value that matches the preselected value on re-render', () => {
 59	    onSelect = jest.fn();
 60	    const { rerender } = render(
 61	      <TypeaheadDropdown items={items} onSelect={onSelect} />
 62	    );
 63	
 64	    expect(getTypeaheadDropdown(screen)).toHaveValue('');
 65	    expect(onSelect).not.toHaveBeenCalled();
 66	
 67	    rerender(<TypeaheadDropdown items={items} selectedValue="200" />);
 68	
 69	    expect(getTypeaheadDropdown(screen)).toHaveValue(items[3].children);
 70	    expect(onSelect).not.toHaveBeenCalled();
 71	  });
 72	
 73	  it('selects the option value selected by the user', async () => {
 74	    const user = userEvent.setup();
 75	    onSelect = jest.fn();
 76	    render(<TypeaheadDropdown items={items} onSelect={onSelect} />);
 77	
 78	    const typeaheadDropdown = getTypeaheadDropdown(screen);
 79	    await user.click(typeaheadDropdown);
 80	    await user.click(getOption(screen, items[3].children) as Element);
 81	
 82	    expect(typeaheadDropdown).toHaveValue(items[3].children);
 83	    expect(onSelect).toHaveBeenCalledTimes(1);
 84	    expect(onSelect).toHaveBeenCalledWith(items[3].value);
 85	  });
 86	
 87	  it('clears the value on "Clear Button" click', async () => {
 88	    const user = userEvent.setup();
 89	    onSelect = jest.fn();
 90	    render(
 91	      <TypeaheadDropdown
 92	        items={items}
 93	        selectedValue={100}
 94	        onSelect={onSelect}
 95	      />
 96	    );
 97	
 98	    const typeaheadDropdown = getTypeaheadDropdown(screen);
 99	    expect(typeaheadDropdown).toHaveValue(items[0].children);
100	
101	    const clearButton = screen.getByRole('button', {
102	      name: /clear selected value/i,
103	    });
104	    expect(clearButton).toBeVisible();
105	    await user.click(clearButton);
106	
107	    expect(typeaheadDropdown).toHaveValue('');
108	    expect(onSelect).toHaveBeenCalledTimes(1);
109	    expect(onSelect).toHaveBeenCalledWith('');
110	  });
111	
112	  it('shows the options matching the typed text (typeahead)', async () => {
113	    const user = userEvent.setup();
114	    render(<TypeaheadDropdown items={items} />);
115	
116	    const typeaheadDropdown = getTypeaheadDropdown(screen);
117	    await user.click(typeaheadDropdown);
118	
119	    expect(getOption(screen, items[0].children)).toBeVisible();
120	
121	    await user.type(typeaheadDropdown, '12');
122	
123	    expect(getOption(screen, items[0].children)).not.toBeInTheDocument();
124	    expect(getOption(screen, items[1].children)).toBeVisible();
125	    expect(getOption(screen, items[2].children)).toBeVisible();
126	    expect(getOption(screen, items[3].children)).not.toBeInTheDocument();
127	    expect(getOption(screen, items[4].children)).toBeVisible();
128	
129	    await user.type(typeaheadDropdown, '5');
130	
131	    expect(getOption(screen, items[0].children)).not.toBeInTheDocument();
132	    expect(getOption(screen, items[1].children)).not.toBeInTheDocument();
133	    expect(getOption(screen, items[2].children)).toBeVisible();
134	    expect(getOption(screen, items[3].children)).not.toBeInTheDocument();
135	    expect(getOption(screen, items[4].children)).not.toBeInTheDocument();
136	  });
137	});

